<?php declare(strict_types=1); require_once dirname(__DIR__) . '/config/bootstrap.php'; ns_redirect_legacy_url('/ferramentas/calculadora-juros-atraso'); ns_render_page_start('tool:calculadora-juros-atraso'); ?>
<main><div class="tool-page"><nav class="breadcrumb" aria-label="Navegação breadcrumb"><a href="<?= ns_escape(ns_href('/')) ?>">Início</a><span class="sep">›</span><a href="<?= ns_escape(ns_href('/ferramentas')) ?>">Ferramentas</a><span class="sep">›</span><span>Calculadora de Juros por Atraso</span></nav><?php ns_render_ad_slot('leaderboard'); ?><div class="tool-header"><div class="tool-page-icon" style="background:linear-gradient(135deg,#eef7ff,#d6e8ff);">📅</div><div><h1>Calculadora de Juros por Atraso</h1><p>Descubra rapidamente o valor de juros simples por atraso com base em taxa e período informado.</p><span class="tag tag-blue">Finanças</span></div></div><div class="tool-box"><div class="form-row"><div class="form-group"><label for="ja-valor">Valor (R$)</label><input id="ja-valor" class="form-control" type="number" min="0" step="0.01"></div><div class="form-group"><label for="ja-taxa">Taxa ao mês (%)</label><input id="ja-taxa" class="form-control" type="number" min="0" step="0.01"></div><div class="form-group"><label for="ja-dias">Dias de atraso</label><input id="ja-dias" class="form-control" type="number" min="0" step="1"></div></div><div class="form-row"><button class="btn btn-primary" type="button" onclick="calcJA()">Calcular</button><button class="btn btn-outline" type="button" onclick="clearJA()">Limpar</button><button class="copy-btn" type="button" onclick="copyJA(this)">Copiar resultado</button></div><div class="notice notice-warn" id="ja-erro" style="display:none;"><span>⚠️</span><span id="ja-erro-texto"></span></div><div class="result-box" id="ja-res"><div class="result-grid"><div class="result-item"><div class="label">Juros</div><div class="value" id="ja-juros-res">—</div></div><div class="result-item"><div class="label">Total atualizado</div><div class="value" id="ja-total-res">—</div></div></div><div id="ja-det" style="margin-top:1rem;color:var(--text2);"></div></div></div><?php ns_render_ad_slot('rectangle'); ?><div class="seo-content"><h2>O que é essa ferramenta</h2><p>Esta página calcula juros simples de atraso para pagamentos, mensalidades, cobranças e acordos. É uma forma rápida de conferir atualização financeira sem depender de planilhas.</p><h2>Como usar</h2><p>Digite o valor original, a taxa mensal e a quantidade de dias de atraso. O cálculo proporcional é exibido imediatamente com juros e total.</p><h2>Exemplo de uso</h2><p>Uma cobrança de R$ 1.000 com juros de 1% ao mês por 10 dias terá um acréscimo proporcional simples, mostrado automaticamente na tela.</p><h2>Perguntas frequentes</h2><h3>O cálculo usa juros compostos?</h3><p>Não. Nesta versão, o cálculo usa juros simples proporcionais.</p><h3>Serve para boletos?</h3><p>Sim, como referência rápida para conferência.</p><h3>É cálculo oficial?</h3><p>Use como estimativa. Regras contratuais e legais específicas podem variar.</p></div></div></main><script>const jaValor=document.getElementById('ja-valor'),jaTaxa=document.getElementById('ja-taxa'),jaDias=document.getElementById('ja-dias'),jaJurosRes=document.getElementById('ja-juros-res'),jaTotalRes=document.getElementById('ja-total-res'),jaDet=document.getElementById('ja-det'); function jaErr(m){document.getElementById('ja-erro-texto').textContent=m;document.getElementById('ja-erro').style.display='flex';document.getElementById('ja-res').classList.remove('show')} function jaClearErr(){document.getElementById('ja-erro').style.display='none'} function calcJA(){const v=parseFloat(jaValor.value),t=parseFloat(jaTaxa.value),d=parseInt(jaDias.value||'0',10);jaClearErr();if(isNaN(v)||isNaN(t)||isNaN(d)||v<=0||t<0||d<0){jaErr('Informe valor, taxa e dias válidos.');return}const juros=v*(t/100)*(d/30),total=v+juros;jaJurosRes.textContent='R$ '+fmtBRL(juros);jaTotalRes.textContent='R$ '+fmtBRL(total);jaDet.textContent='Juros simples proporcionais aos dias informados.';showResult('ja-res')} function clearJA(){jaValor.value='';jaTaxa.value='';jaDias.value='';document.getElementById('ja-res').classList.remove('show');jaClearErr()} function copyJA(b){if(!document.getElementById('ja-res').classList.contains('show')){jaErr('Calcule antes de copiar.');return}copyToClipboard('Juros: '+jaJurosRes.textContent+'\nTotal: '+jaTotalRes.textContent,b)}</script><?php ns_render_page_end(); ?>
